"use client";

import { useEffect, useMemo, useState } from "react";
import { useAccount, useBalance, useSendTransaction } from "wagmi";
import { parseEther } from "viem";
import { io } from "socket.io-client";

import { TOKENS } from "@/lib/tokens";
import {
  sendTx as backendSendTx,
  } from "@/lib/api";

  const socket = io("https://iopndex.onrender.com");

  function formatBalance(value: any) {
    if (!value) return "0.00";
      return Number(value.formatted || 0).toFixed(4);
      }

      export default function PayPage() {
        const { address, isConnected } = useAccount();

          const [recipient, setRecipient] = useState("");
            const [amount, setAmount] = useState("");
              const [tokenSymbol] = useState("OPN");
                const [txHash, setTxHash] = useState<string | null>(null);
                  const [liveTxs, setLiveTxs] = useState<any[]>([]);
                    const [sending, setSending] = useState(false);

                      const token = useMemo(
                          () => TOKENS.find((t) => t.symbol === tokenSymbol)!,
                              [tokenSymbol]
                                );

                                  const { data: balance } = useBalance({
                                      address,
                                        });

                                          const { sendTransactionAsync } = useSendTransaction();

                                            async function sendTx() {
                                                if (!isConnected || !address) {
                                                      alert("Connect your wallet first.");
                                                            return;
                                                                }

                                                                    if (!recipient || !amount) {
                                                                          alert("Please fill all fields.");
                                                                                return;
                                                                                    }

                                                                                        try {
                                                                                              setSending(true);

                                                                                                    const hash = await sendTransactionAsync({
                                                                                                            to: recipient as `0x${string}`,
                                                                                                                    value: parseEther(amount),
                                                                                                                          });

                                                                                                                                setTxHash(hash);

                                                                                                                                      const result = await backendSendTx(
                                                                                                                                              address,
                                                                                                                                                      recipient,
                                                                                                                                                              amount,
                                                                                                                                                                      token.symbol,
                                                                                                                                                                              hash,
                                                                                                                                                                                      984
                                                                                                                                                                                            );

                                                                                                                                                                                                  if (!result.success) {
                                                                                                                                                                                                          alert(result.error || "Backend error");
                                                                                                                                                                                                                  return;
                                                                                                                                                                                                                        }

                                                                                                                                                                                                                              setRecipient("");
                                                                                                                                                                                                                                    setAmount("");

                                                                                                                                                                                                                                          alert("Transaction submitted successfully 🚀");
                                                                                                                                                                                                                                              } catch (err) {
                                                                                                                                                                                                                                                    console.error(err);
                                                                                                                                                                                                                                                          alert("Transaction cancelled or failed.");
                                                                                                                                                                                                                                                              } finally {
                                                                                                                                                                                                                                                                    setSending(false);
                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                            useEffect(() => {
                                                                                                                                                                                                                                                                                socket.on("newTx", (tx) => {
                                                                                                                                                                                                                                                                                      setLiveTxs((prev) => [tx, ...prev]);
                                                                                                                                                                                                                                                                                          });

                                                                                                                                                                                                                                                                                              socket.on("txConfirmed", (tx) => {
                                                                                                                                                                                                                                                                                                    setLiveTxs((prev) =>
                                                                                                                                                                                                                                                                                                            prev.map((item) =>
                                                                                                                                                                                                                                                                                                                      item.hash === tx.hash
                                                                                                                                                                                                                                                                                                                                  ? {
                                                                                                                                                                                                                                                                                                                                                  ...item,
                                                                                                                                                                                                                                                                                                                                                                  status: "confirmed",
                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                            : item
                                                                                                                                                                                                                                                                                                                                                                                                    )
                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                                                                                                                                  return () => {
                                                                                                                                                                                                                                                                                                                                                                                                                        socket.off("newTx");
                                                                                                                                                                                                                                                                                                                                                                                                                              socket.off("txConfirmed");
                                                                                                                                                                                                                                                                                                                                                                                                                                  };
                                                                                                                                                                                                                                                                                                                                                                                                                                    }, []);

                                                                                                                                                                                                                                                                                                                                                                                                                                      return (
                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="min-h-screen bg-black text-white px-5 py-8">
                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="max-w-md mx-auto">

                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="rounded-3xl bg-gradient-to-r from-green-500 to-emerald-700 p-6 shadow-xl mb-8">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h1 className="text-3xl font-bold">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              IOPN Pay
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </h1>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-white/80 mt-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Send assets securely on IOPN Testnet
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="mt-5 rounded-2xl bg-black/20 p-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-sm text-white/70">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Balance
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <h2 className="text-2xl font-bold">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {formatBalance(balance)} {token.symbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {txHash && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="mt-4 break-all text-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Last Tx:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <br />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {txHash}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="rounded-3xl bg-zinc-900 p-5 space-y-4 shadow-lg">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="w-full rounded-xl bg-zinc-800 p-4 outline-none"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                placeholder="Recipient Address"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            value={recipient}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onChange={(e) => setRecipient(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="w-full rounded-xl bg-zinc-800 p-4 outline-none"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    placeholder="Amount"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={amount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={(e) => setAmount(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onClick={sendTx}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        disabled={sending}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="w-full rounded-xl bg-green-500 py-4 font-bold text-black"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {sending ? "Sending..." : "Send OPN"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="mt-10">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h2 className="text-xl font-bold mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Live Transactions
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </h2>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {liveTxs.length === 0 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="text-white/50">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        No transactions yet.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {liveTxs.map((tx, index) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  key={index}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="rounded-2xl bg-zinc-900 p-4 mb-4"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="text-sm break-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {tx.from}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="text-xs text-white/50 mt-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ↓
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="text-sm break-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {tx.to}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="mt-3 text-green-400 font-bold">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {tx.amount} OPN
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="text-xs text-white/50 mt-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Status: {tx.status || "pending"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }